const text = $json.text || "";

if (!text) {
  throw new Error("No text provided.");
}

if (!$json.body?.doc_id) {
  throw new Error("No doc_id provided.");
}

const docId = $json.body.doc_id;
const title = $json.body.title || "";
const developer = $json.body.developer || "";
const project = $json.body.project || "";
const community = $json.body.community || "";
const documentType = $json.body.document_type || "";
const year = $json.body.year || "";

const CHUNK_SIZE = 1000;
const CHUNK_OVERLAP = 200;

const isArabic = /[\u0600-\u06FF]/.test(text);

const chunks = [];
let chunkId = 1;

for (let i = 0; i < text.length; i += CHUNK_SIZE - CHUNK_OVERLAP) {

  let end = Math.min(i + CHUNK_SIZE, text.length);

  // Don't search if this is the last chunk
  if (end < text.length) {

    // Look back up to 200 characters for a better place to split
    const searchStart = Math.max(i, end - 200);
    const searchText = text.slice(searchStart, end);

    // Prefer paragraph break
    let split = searchText.lastIndexOf("\n\n");

    // Otherwise line break
    if (split === -1) split = searchText.lastIndexOf("\n");

    // Otherwise sentence end
    if (split === -1) split = searchText.lastIndexOf(".");

    // Otherwise space
    if (split === -1) split = searchText.lastIndexOf(" ");

    // Found a better boundary
    if (split > 0) {
      end = searchStart + split;
    }
  }

  const chunkText = text.slice(i, end).trim();

  // Skip tiny chunks only if they are NOT the final chunk
  if (chunkText.length < 200 && end < text.length) {
    continue;
  }

  const chunkData = {
    json: {
      doc_id: docId,
      chunk_id: chunkId++,
      title,
      developer,
      project,
      community,
      document_type: documentType,
      year,
      chunk: chunkText,
      language: isArabic ? "ar" : "en",
      supported_languages: ["en", "ar"]
    }
  };

  chunks.push(chunkData);

  // Stop after saving the final chunk
  if (end >= text.length) {
    break;
  }
}

return chunks;

