// Number of processed chunks
const chunksProcessed = $input.all().length;

// Get the original request from the Webhook node
const originalRequest = $('Webhook').first().json.body;

return [
  {
    json: {
      success: true,
      doc_id: originalRequest.doc_id,
      title: originalRequest.title,
      chunks_processed: chunksProcessed,
      message: "Document ingested successfully.",
      timestamp: new Date().toISOString()
    }
  }
];

const item = $input.first();
let text = item.json.text || "";

const documentType = ($json.body?.document_type || "")
  .trim()
  .toLowerCase();

// Normalize line endings
text = text.replace(/\r\n/g, "\n");

// Remove URLs
text = text.replace(/https?:\/\/\S+|www\.\S+/gi, "");


// Remove lines made only of OCR symbols
text = text.replace(/^[\s|._-]+$/gm, "");

// Remove lines containing only pipes
text = text.replace(/^\s*\|\s*$/gm, "");

// Remove lines containing only dots
text = text.replace(/^\s*\.{2,}\s*$/gm, "");

// Collapse multiple blank lines
text = text.replace(/\n{3,}/g, "\n\n");

// Collapse multiple spaces
text = text.replace(/[ \t]{2,}/g, " ");

// Remove trailing spaces on each line
text = text.replace(/[ \t]+$/gm, "");

// Trim
text = text.trim();

// ---------- Document-specific cleaning ----------
if (documentType === "payment plan") {

  // Remove email addresses
  text = text.replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, "");

  // Remove UAE phone numbers
  text = text.replace(/(\+971[\s-]?\d[\d\s-]{7,}|0\d[\d\s-]{7,})/g, "");

  // Remove marketing labels
  text = text.replace(
    /\b(CONTACT US|FOR MORE INFO|VISIT WEBSITE|EMAIL US|ADDRESS)\b:?/gi,
    ""
  );

}
// Save cleaned text for EVERY document
item.json.text = text;
return [item];
